window.__QUIZ_DATA__=[{"id":"objective>Physics>2000>1","subject":"Physics","year":"2000","type":"Objective","topic":"CONCEPTS OF MATTER : CONCEPTS OF MATTER","question":"When the surface of a piece of chalk is scrapped the tiny particles that flake off are known as","images":[],"options":{"A":"matter","B":"molecules","C":"elements","D":"atoms"},"answer":"D","explanation":"Matter is anything that takes up space and has mass. While the chalk dust is certainly matter, it's not a specific term for the particles themselves.    Atoms are the smallest units of matter that retain the chemical properties of an element. Therefore, the individual particles of chalk dust are indeed atoms.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2000>2","subject":"Physics","year":"2000","type":"Objective","topic":"FUNDAMENTAL AND DERIVED QUANTITIES AND UNITS : MEASUREMENT OF DISTANCE","question":"Thediagramaboverepresentasectionofapairofverniercallipers.thereadingontheinstrumentis","images":["data:image/png;base64,"],"options":{"A":"5.22 cm","B":"5.24 cm","C":"5.25 cm","D":"5.26 cm"},"answer":"D","explanation":"From the main scale, we have 5.2cm  (this is the last reading before & zero on the venier scale)  The reading on the vernier scale is 0.06cm  (where the main and vernier sccale coincides)    Reading = 5.2 + 0.06 = 5.26cm","marks":"1","difficulty":"2"},{"id":"objective>Physics>2000>3","subject":"Physics","year":"2000","type":"Objective","topic":"MASS AND WEIGHT : DISTINCTION BETWEEN MASS AND WEIGHT","question":"An iron rod is moved from the earth to the moon. which of the following remains unchanged?.  I. mass  II. weight  III. relative density","images":[],"options":{"A":"I only","B":"II only","C":"III only","D":"I and III only"},"answer":"D","explanation":"Mass and relative density is always constant.  Weight varies, because gravity on the earth and moon are not the same.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2000>4","subject":"Physics","year":"2000","type":"Objective","topic":"FLUID AT REST : VOLUME, DENSITY AND RELATIVE DENSITY","question":"A uniform cylindrical hydrometer of mass 20g and cross sectional area 0.54cm2 floats upright in a liquid. if 25cm of its length is submerged, calculate the relative density of he liquid.[Density of water = 1g cm3]","images":[],"options":{"A":"1.54","B":"1.48","C":"1.25","D":"0.80"},"answer":"B","explanation":"Mass = 20g  Cross sectional area = 0.54cm2  Length = 25cm  Volume = area x length  V = 0.54 x 25 = 13.5cm3  Density=MV=2013.5=1.48gcm-3  R.D=Density of substanceDensity of water=1.481=1.48","marks":"1","difficulty":"3"},{"id":"objective>Physics>2000>5","subject":"Physics","year":"2000","type":"Objective","topic":"FLUID AT REST : EQUILIBRIUM OF BODIES: ARCHIMEDES\u2019 PRINCIPLE","question":"The apparent weight of a body wholly immersed in water is 32N and its weight in air 96N. calculate the volume of the body. density of water = 1000kg m3, g = 10ms2","images":[],"options":{"A":"8.9 \u00d710-3 m3","B":"6.4 \u00d710-3 m3","C":"3.2 \u00d710-3m3","D":"3.0 \u00d7 10-3m3"},"answer":"B","explanation":"Apparent weight = 32N  Real weight = 96N  Density of water = 1000kgm-3  acceleration (g) = 10ms-2    Upthrust = Real weight - Apparent weight  \u21d2 96N - 32N = 64N    Upthrust = weight of body displaced  Weight of body = Vpg  gb = density  V=64gb=6410,000=6.4x10-3m3","marks":"1","difficulty":"2"},{"id":"objective>Physics>2000>6","subject":"Physics","year":"2000","type":"Objective","topic":"MOTION : SOLID FRICTION","question":"A wooden block of mass 1.6kg rest on a rough horizontal surface. if the limiting frictional force between the block and the surface is 8N, calculate the coefficient of friction [g = 10ms-2]","images":[],"options":{"A":"0.6","B":"0.5","C":"0.3","D":"0.2"},"answer":"B","explanation":"Wooden block weighs 1.6kg  Force = 8N  g = 10m/s2  Coefficientoffriction=FR  Reaction (R) = mg  R = 1.6 x 10 = 16N  \u03bc=8N16N=0.5","marks":"1","difficulty":"2"},{"id":"objective>Physics>2000>7","subject":"Physics","year":"2000","type":"Objective","topic":"MOTION : VISCOSITY (FRICTION IN FLUIDS)","question":"A ball bearing is gently released from rest and allowed to fall through a viscous fluid. which of the following statement about the motion is correct?","images":[],"options":{"A":"its acceleration decreases before terminal velocity is attained","B":"when terminal velocity is attained the acceleration of the fluid becomes zero","C":"its velocity increases before terminal velocity is attained","D":"velocity"},"answer":"B","explanation":"After terminal velocity is reached, the net acceleration of the body falling through a fluid is zero because the body after attaining terminal velocity will continue moving with same velocity through the viscous medium.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2000>8","subject":"Physics","year":"2000","type":"Objective","topic":"MOTION : RELATIVE MOTION","question":"The driver of a car moving with a uniform speed of 40ms-1 observes a truck approaching in the opposite direction with a speed of 20ms-1. calculate the speed of the car relative to that of the truck.","images":[],"options":{"A":"0.5ms-1","B":"2.0ms-1","C":"20.0ms-1","D":"60.0ms-1"},"answer":"D","explanation":"Since they are moving in opposite directions   relative speed of the car to the truck is = 40 + 20 = 60m/s","marks":"1","difficulty":"1"},{"id":"objective>Physics>2000>9","subject":"Physics","year":"2000","type":"Objective","topic":"RECTILINEAR ACCELERATION : EQUATIONS OF MOTION WITH CONSTANT ACCELERATION","question":"A bus travelling at 15ms-1 accelerates uniformly at 4ms-2 what is the distance covered in 10s?","images":[],"options":{"A":"150m","B":"170m","C":"350m","D":"600m"},"answer":"C","explanation":"Initial speed = 15m/s  acceleration = 4m/s2  time = 10s     Using 2nd Newton's law of motion,  s=ut+12at2  s=15x10+12x102x4  s = 150 + 200  s = 350m","marks":"1","difficulty":"2"},{"id":"objective>Physics>2000>10","subject":"Physics","year":"2000","type":"Objective","topic":"MOTION : SIMPLE IDEAS OF CIRCULAR MOTION","question":"Which of the following sketches represents the velocity-time graph of the motion of a stone projected vertically upwards and allowed to return to the point of projection?","images":["data:image/png;base64,","data:image/png;base64,","data:image/png;base64,","data:image/png;base64,"],"options":{"A":"","B":"","C":"","D":""},"answer":"B","explanation":"This graph shows the stones comes back to rest, to its original status","marks":"1","difficulty":"3"},{"id":"objective>Physics>2000>11","subject":"Physics","year":"2000","type":"Objective","topic":"EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES","question":"The diagram above illustrates three forces T1, T2 and 100N in equilibrium. Determine the magnitude of T","images":["data:image/png;base64,"],"options":{"A":"100 tan 30\u2218","B":"100cos30\u2218","C":"200sin30\u2218","D":"200tan30\u2218"},"answer":"A","explanation":"Therefore,  T1 = 100 tan 30\u2218    the magnitude of T = 100 tan 30\u2218.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2000>12","subject":"Physics","year":"2000","type":"Objective","topic":"EQUILIBRIUM OF FORCES : CENTRE OF GRAVITY AND STABILITY","question":"A uniform meter rule of mass 90g is pivoted at the 40 cm mark. if the rule is in equilibrium with an unknown mass m placed ate the 10cm mark and a 72g mass at the 70cm mark, determine m","images":[],"options":{"A":"72g","B":"102g","C":"198g","D":"504g"},"answer":"B","explanation":"Applying the principle of moment   Anti clockwise = clockwise     m \u00d7 30 = (90 x 10) + (72 x 30)  30m = 900 + 2160  30m = 3060  m=306030=102g","marks":"1","difficulty":"2"},{"id":"objective>Physics>2000>13","subject":"Physics","year":"2000","type":"Objective","topic":"SCALARS AND VECTORS : ADDITION OF VECTORS","question":"The resultant of two forces acting on an object is maximum when the angle between them is?","images":[],"options":{"A":"180\u2218","B":"90\u2218","C":"45\u2218","D":"0\u2218"},"answer":"D","explanation":"The resultant of two forces acting on an object is maximum when the angle between them is 0 degrees. This is because when two forces act in the same direction (i.e., the angle between them is 0 degrees), they add up to give the maximum resultant force. If the angle is anything other than 0 degrees, the resultant force will be less than the sum of the two forces due to the vector nature of forces.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2000>14","subject":"Physics","year":"2000","type":"Objective","topic":"SIMPLE HARMONIC MOTION : PERIOD, FREQUENCY AND AMPLITUDE OF A BODY EXECUTING S.H.M","question":"The bob of a simple pendulum takes 0.25s to swing from its equilibrium position to one extreme end. calculate its period","images":[],"options":{"A":"0.25s","B":"0.50s","C":"0.75s","D":"1.00s"},"answer":"D","explanation":"Time taken to swing from equilibrium position to one extreme end, which is 1/4 period, is 0.25s  Period for 1 oscillation = 0.25s \u00d7 4 = 1.00s","marks":"1","difficulty":"1"},{"id":"objective>Physics>2000>15","subject":"Physics","year":"2000","type":"Objective","topic":"SIMPLE HARMONIC MOTION : SPEED AND ACCELERATION OF S.H.M","question":"The period of oscillation of a particle executing simple harmonic motion is 4\u22bc seconds. if the amplitude of oscillation is 3.0m, calculate the maximum speed of the particle.","images":[],"options":{"A":"1.5ms-1","B":"3.0ms-1","C":"4.5ms-1","D":"6.0ms-1"},"answer":"A","explanation":"T = 4\u03c0, r = 3.0m, V = ?  since V = wr  andw=2\u03c0T  substituting for T = 4\u03c0  w=2\u03c04\u03c0=12  Therefore,  V = wr  V=12\u00d73.0=1.5ms-1","marks":"1","difficulty":"3"},{"id":"objective>Physics>2000>16","subject":"Physics","year":"2000","type":"Objective","topic":"WORK, ENERGY AND POWER : CONCEPT OF WORK","question":"An inelastic collision takes place between balls of known masses. just before the collision one of the balls is moving with a known velocity while other is stationary, which of the following physical quantities can be determined from the information given?","images":[],"options":{"A":"speed of each of the ball after collision","B":"kinetic energy of each ball afer collision","C":"total momentum of the two balls after collision","D":"mutual forces exerted by the balls"},"answer":"C","explanation":"In an inelastic collision, the total momentum before the collision is equal to the total momentum after the collision. This is known as the law of conservation of momentum. Therefore, we can determine the total momentum of the two balls after the collision. However, we cannot determine the speed or kinetic energy of each ball after the collision, or the mutual forces exerted by the balls, from the information given. Therefore, the correct option is 3.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2000>17","subject":"Physics","year":"2000","type":"Objective","topic":"WORK, ENERGY AND POWER : WORK DONE IN A GRAVITATIONAL FIELD","question":"Using the force-displacement diagram shown above, calculate the work done.","images":["data:image/png;base64,"],"options":{"A":"2000J","B":"1000J","C":"20J","D":"5J"},"answer":"A","explanation":"Work done  = force x displacement    = 100 x 20   = 2000J","marks":"1","difficulty":"3"},{"id":"objective>Physics>2000>18","subject":"Physics","year":"2000","type":"Objective","topic":"WORK, ENERGY AND POWER : CONCEPT OF POWER","question":"A machine of efficiency 80% is used to raise a body of mass 75kg through a vertical height of 3m in 30s. calculate the power input.[g  = 10ms-1]","images":[],"options":{"A":"9.4w","B":"60.0w","C":"75.0w","D":"93.8 w"},"answer":"D","explanation":"Efficiency=work outputwork input=80100=75 x 10 x 3work input  80 x work input = 75 x 10 x 3   workinput=75 x 10 x 3 x 10080  =75 x 3 x 252  Power=work inputtime  =75 x 3 x 252 x 30=3754=93.75","marks":"1","difficulty":"3"},{"id":"objective>Physics>2000>19","subject":"Physics","year":"2000","type":"Objective","topic":"HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT","question":"Two bodies, P and Q are in thermal equilibrium. which of the following statement about the bodies is correct?","images":[],"options":{"A":"the temperature of Q is higher than that of P","B":"p and Q have the same capacity","C":"P and Q have the same mass","D":"P and Q are the same temperature"},"answer":"D","explanation":"A condition where two bodies in contact no longer exchange heat, they are of the same temperature","marks":"1","difficulty":"1"},{"id":"objective>Physics>2000>20","subject":"Physics","year":"2000","type":"Objective","topic":"HEAT ENERGY : THERMAL EXPANSION","question":"The cubic expansivity of mercury is 1.8 \u00d710-4k1  and the linear expansivity of glass is 8.0 \u00d710-6k-1. calculate the apparent expansivity of the mercury glass container.","images":[],"options":{"A":"100 \u00d710-4k-1","B":"1.56 \u00d710-4K-1","C":"1.72 \u00d7 10\u00d7 104k-1","D":"2.4 \u00d7 10-4k-1"},"answer":"B","explanation":"\u03b4r is the real cubic expansivity  \u03b4a is the apparent cubic expansivity  \u03b4 is the cubic expansivity of the vessel     Cubic expansivity of the vessel = 3 x expansivity of material   \u21d2 3 x 8.0 x 10-6 = 24.0 x 10-6  \u21d2 2.4 x 10-5  \u03b4r = \u03b4a + \u03b4  \u03b4a = \u03b4r - \u03b4  substituting,  \u03b4a = 1.8 x 10-4 - 2.4 x 10-5  \u21d2 1.8 x 10-4 - 0.24 x 10-4  \u21d2 (1.8 - 0.24) x 10-4  \u21d2 1.56 x 10-4","marks":"1","difficulty":"3"},{"id":"objective>Physics>2000>21","subject":"Physics","year":"2000","type":"Objective","topic":"HEAT ENERGY : GAS LAWS","question":"Thediagramaboveshowsthevariationofvolumevofaglasswithtemperature0inacharles'law experiment.thevalueofthetemperatureatthepointsxis","images":["data:image/png;base64,"],"options":{"A":"-32\u2218c","B":"-100\u2218c","C":"-273\u2218c","D":"-373\u2218c"},"answer":"C","explanation":"According to charle's law,  at -273\u00b0C the volume is assumed to be zero (0).","marks":"1","difficulty":"2"},{"id":"objective>Physics>2000>22","subject":"Physics","year":"2000","type":"Objective","topic":"HEAT ENERGY : GAS LAWS","question":"The volume and pressure of a given mass at 27\u2218c are 76cm3 and 80cm of mercury respectively. calculate its volume at s.t.p","images":[],"options":{"A":"36.2cm","B":"72.8cm","C":"100.0cm","D":"808.9cm"},"answer":"B","explanation":"P1V1T1=P2V2T2  T1 = 27\u00b0C = 27 + 273 = 300K  P1 = 80cmHg = 800mmHg  V1 = 76cm3    T2 = 273K  P2 = 760mmHg  V2 = ?  Making V2 the subject of formular  V2=P1V1T2P2T1  V2=800 x 76 760=72.8cm2","marks":"1","difficulty":"2"},{"id":"objective>Physics>2000>23","subject":"Physics","year":"2000","type":"Objective","topic":"HEAT ENERGY : HEAT CAPACITY","question":"A piece of metal of mass 50g is cooled from 80\u2218c to 20\u2218c calculate the amount of heat lost.[specify heat capacity of the material of metal  = 450Jkg-1k-1]","images":[],"options":{"A":"4.50 \u00d7 103 J","B":"2.25 \u00d7103 J","C":"1.80 \u00d7 103 J","D":"1.35 \u00d7 103 J"},"answer":"D","explanation":"H = mc\u0394\u03b8  substituting values in,   H = 0.05 x 450 x (80 - 20)  H = 0.05 x 450 x 60 = 1350J  H = 1.35 x 103J","marks":"1","difficulty":"2"},{"id":"objective>Physics>2000>24","subject":"Physics","year":"2000","type":"Objective","topic":"HEAT ENERGY : HUMIDITY, RELATIVE HUMIDITY AND DEW POINT","question":"The mass of water vapour in a given volume of air is 0.05 g  at 20\u2218c, while the mass of water vapour required to saturate it at the same temperature is 0.15g. calculate the relative humidity of air","images":[],"options":{"A":"3.33%","B":"5.55%","C":"33.3%","D":"55.5%"},"answer":"C","explanation":"Relative humidity is the ratio of the actual amount of water vapour present in the air to the maximum amount of water vapour the air could hold at that temperature, expressed as a percentage. Here, the actual amount of water vapour is 0.05g and the maximum amount of water vapour the air could hold at 20\u00b0C is 0.15g. Therefore, the relative humidity is (0.05g / 0.15g) * 100% = 33.3%. Therefore, the correct answer is 33.3%.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2000>25","subject":"Physics","year":"2000","type":"Objective","topic":"HEAT ENERGY : BOILING POINT","question":"The temperature at which the saturated vapour pressure of liquid is equal to the external atmospheric pressure is known as","images":[],"options":{"A":"dew point","B":"boiling point","C":"lower fixed point","D":"tripple point"},"answer":"B","explanation":"When a liquid is exposed to atmospheric pressure, it boils when its saturated vapour pressure equals 1 atmospheric pressure (101325Pa)","marks":"1","difficulty":"2"},{"id":"objective>Physics>2000>26","subject":"Physics","year":"2000","type":"Objective","topic":"PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(\ud835\udecc), PERIOD (T) AND VELOCITY (V)","question":"A periodic pulse travels a distance of 20.0m in 1.00s. if its frequency is 2.0 \u00d7 103Hz, calculate the wavelength","images":[],"options":{"A":"1.0\u00d7103m","B":"1.0 \u00d7 102m","C":"2.0 \u00d7 102m","D":"1.0 \u00d7 10-2m"},"answer":"D","explanation":"V = F\u22cb  making \u22cb the subject of formular   \u22cb=VF=202.0 x 103=10x10-3 = 10-2m","marks":"1","difficulty":"3"},{"id":"objective>Physics>2000>27","subject":"Physics","year":"2000","type":"Objective","topic":"SIMPLE HARMONIC MOTION : SPEED AND ACCELERATION OF S.H.M","question":"A wave has an amplitude equal to 4.0m .The displacement y of the 1/3\u22bc rad s-1 and phase angle 2/3\u22bc rad. The displacement y of the wave particle is given as","images":[],"options":{"A":"y = 4 sin \u22bc/3 (t-2)","B":"y = 4 sin\u22bc/3(t+2/\u22bc)","C":"y = 4 sin \u22bc/3(2t+1)","D":"y  = 4 sin\u22bc/3(t+2)"},"answer":"D","explanation":"y = Asin(\u03c9t + \u2205)  substituting  y=Asin(\u03c03t +2\u03c03)  y=4sin\u03c03(t+2)","marks":"1","difficulty":"3"},{"id":"objective>Physics>2000>28","subject":"Physics","year":"2000","type":"Objective","topic":"LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES","question":"In the diagram above, an incident ray AY makes an angle an angle makes an angle of 30\u2218 with the normal XY, if the mirror is rotated anticlockwise about Y through an angle of 20\u2218, while AY is fixed, what angle will the reflected ray now make with the incident ray","images":["data:image/png;base64,"],"options":{"A":"70\u2218","B":"80\u2218","C":"100\u2218","D":"120\u2218"},"answer":"C","explanation":"The new incident ray becomes = 30\u00b0 + 20\u00b0 = 50\u00b0  (since the mirror was rotated by 20\u00b0)  Therefore, the reflected ray = 50\u00b0  angle between incident ray and reflected ray = 50\u00b0 + 50\u00b0 = 100\u00b0","marks":"1","difficulty":"3"},{"id":"objective>Physics>2000>29","subject":"Physics","year":"2000","type":"Objective","topic":"LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES","question":"A concave mirror can be used to produce a parallel beam of light if a lighted bulb is placed","images":[],"options":{"A":"between its focus and the pole","B":"at its focus","C":"at its center of curvature","D":"between its focus and center of curvature"},"answer":"B","explanation":"A concave mirror can be used to produce a parallel beam of light if a lighted bulb is placed at its focus. This is because the rays of light from the bulb, which are incident on the mirror, will reflect off the mirror and travel parallel to each other. Hence, option 2 is correct.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2000>30","subject":"Physics","year":"2000","type":"Objective","topic":"LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS","question":"A  simple miscroscope forms an image 10cm from an eye close to the lens. if the object is 6cm from the eye , calculate the focal length of the lens","images":[],"options":{"A":"3.75cm","B":"4.00cm","C":"15.00 cm","D":"16.00cm"},"answer":"A","explanation":"Len formular,  1U+1V=1f  1f=110+16  3+530=830  F=308=3.75cm","marks":"1","difficulty":"3"},{"id":"objective>Physics>2000>31","subject":"Physics","year":"2000","type":"Objective","topic":"LIGHT WAVES : DISPERSION OF WHITE LIGHT","question":"When white light passes through a triangular glass prism, there is dispersion because of","images":[],"options":{"A":"diffraction of light","B":"polarisation of light","C":"the difference of light wave in glass","D":"the interference of light waves in glass"},"answer":"C","explanation":"The wavelength hence speed of each of the light components vary, therefore they leave at different angles.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2000>32","subject":"Physics","year":"2000","type":"Objective","topic":"SOUND WAVES : SPEED OF SOUND","question":"In which of the following media does sound travel fastest","images":[],"options":{"A":"water","B":"brass","C":"air","D":"wood"},"answer":"B","explanation":"Sound travels fastest in solids compared to liquids and gases. This is because particles in a solid are closely packed together, allowing sound waves to transfer more quickly from one particle to the next. Among the given options, brass, which is a solid, would allow sound to travel the fastest.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2000>33","subject":"Physics","year":"2000","type":"Objective","topic":"SOUND WAVES : RESONANCE","question":"A turning fork of frequency 600Hz is sounded over a close resonance tube . if the first and second resonant positions are 0.130m and 0.413m respectively, calculate the speed of sound in air.","images":[],"options":{"A":"509.4ms-1","B":"480.0ms-1","C":"339.6ms-1","D":"169.8ms-1"},"answer":"C","explanation":"Since,   F = 600Hz  V = F\u22cb = 2F x (l2 - l1)  and \u22cb = l2 - l1 = (0.413 - 0.130) = 0.283  V = 2 x 600 x (0.413 - 0.130)  V = 2 x 600 x (0.283)  V = 339.6ms-1","marks":"1","difficulty":"3"},{"id":"objective>Physics>2000>34","subject":"Physics","year":"2000","type":"Objective","topic":"SOUND WAVES : RESONANCE","question":"Loudness increases as a vibrating turning fork is brought nearer the end of a pipe containing air column due to","images":[],"options":{"A":"resonance","B":"echo","C":"reverberation","D":"diffraction"},"answer":"A","explanation":"The loudness of a sound increases due to resonance when a vibrating tuning fork is brought nearer to the end of a pipe containing air column. Resonance is a phenomenon that occurs when the frequency of a force applied to a system matches the natural frequency of vibration of the system, resulting in a large amplitude of vibration and hence increased loudness.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2000>35","subject":"Physics","year":"2000","type":"Objective","topic":"SOUND WAVES : HARMONIES AND OVERTONES","question":"The factor which enables the ear to distinguish between a note played on different instrument is the","images":[],"options":{"A":"pitch","B":"speed","C":"harmonic","D":"loudness"},"answer":"C","explanation":"The factor which enables the ear to distinguish between a note played on different instruments is the harmonic. Harmonics are the frequencies that are multiples of the fundamental frequency. Different instruments produce different sets of harmonics, which gives each instrument its unique sound.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2000>36","subject":"Physics","year":"2000","type":"Objective","topic":"GRAVITATIONAL FIELD : ACCELERATION DUE TO GRAVITY","question":"An object is situated within earth's gravitational field. which of the following factors does not affect acceleration of free fall, g?","images":[],"options":{"A":"The distance of the object from the center of the earth","B":"latitude of the earth on which the object is situated","C":"the mass of the object","D":"rotation of the earth"},"answer":"C","explanation":"The acceleration of free fall, g, is not affected by the mass of the object. This is a fundamental principle of gravity that was famously demonstrated by Galileo when he dropped two objects of different masses from the Leaning Tower of Pisa and found that they hit the ground at the same time. The other options, such as the distance of the object from the center of the earth, the latitude of the earth on which the object is situated, and the rotation of the earth, can all affect the value of g.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2000>37","subject":"Physics","year":"2000","type":"Objective","topic":"ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION","question":"The capacitance of the parallel-plate capacitor is increased by making the area of the plates","images":[],"options":{"A":"small and their separation large","B":"large and their separation small","C":"and their seperation small","D":"and their seperation equal"},"answer":"B","explanation":"The larger the area of a capacitor, the increase in capacitance, the smaller the distance of seperation between the plates the higher the capacitance.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2000>38","subject":"Physics","year":"2000","type":"Objective","topic":"ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE","question":"Usethediagramtoanswerthequestion      Inthediagramabove,thecurrentpassingthroughthe6\u03a9resistoris1.5A,calculatethecurrentinthe3\u03a9resistor","images":["data:image/png;base64,"],"options":{"A":"1.2A","B":"0.90A","C":"0.75A","D":"0.60A"},"answer":"D","explanation":"For parallel connection,  effectiveresistance=12+13=56  R=65  Thereforevoltage=1.5\u00d765=1.8    For 3\u03a9 resistor,  I=VR=1.83=0.6A","marks":"1","difficulty":"3"},{"id":"objective>Physics>2000>39","subject":"Physics","year":"2000","type":"Objective","topic":"ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE","question":"Usethediagramtoanswerthequestion    calculate the terminal p.d of the battery in the diagram","images":["data:image/png;base64,"],"options":{"A":"7.5V","B":"9.00V","C":"10.80V","D":"11.25V"},"answer":"C","explanation":"Terminal P.d (VT) = V6 + Vp  where,  V6 = voltage across 6\u03a9 resistor  Vp=95V  VT=9+95=10.8V","marks":"1","difficulty":"3"},{"id":"objective>Physics>2000>40","subject":"Physics","year":"2000","type":"Objective","topic":"HEAT ENERGY : HEAT CAPACITY","question":"An immersion heater is rated 120W. how long does it take the heater to raise the temperature of 1.2kg of water by 15\u2218C. [Assuming heat lost to the surrounding is negligible specific heat capacity of water  = 4200Jkg-1K-1]","images":[],"options":{"A":"65.0 minutes","B":"60.0 minutes","C":"52.5 minutes","D":"10.5 minutes"},"answer":"D","explanation":"Power lost = Power gained (By heater)  P=mc\u0394\u03b8t  therefore,  P x t = mc\u0394\u03b8  t=mc\u0394\u03b8p=1.2 x 4200 x 15120  \u21d2 450 x 15 = 630 seconds    convert to minutes \u21d2 10.5 minutes","marks":"1","difficulty":"3"},{"id":"objective>Physics>2000>41","subject":"Physics","year":"2000","type":"Objective","topic":"MAGNETIC FIELD : CONCEPT OF MAGNETIC FIELD","question":"The region around a magnet in which the magnetic influence experienced is called ?","images":[],"options":{"A":"Magnetic flux","B":"magnetic field","C":"magnetic meridian","D":"magnetic decination"},"answer":"B","explanation":"The region around a magnet where magnetic forces can be detected is called the magnetic field. It is the space around a magnet where the magnetic influence can be experienced. Magnetic flux, on the other hand, is a measure of the total magnetic field which passes through a given area. Magnetic meridian and magnetic declination are terms related to Earth's magnetic field, not a magnet's.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2000>42","subject":"Physics","year":"2000","type":"Objective","topic":"MAGNETIC FIELD : PROPERTIES OF MAGNETS AND MAGNETIC MATERIALS","question":"Ifthebarmagnetisaccidentlybrokenintothreeplaces asshowninthediagrambelow,thepolaritiesofPandQrespectivelyare","images":["data:image/png;base64,"],"options":{"A":"S and S","B":"N and S","C":"N and N","D":"S and N"},"answer":"B","explanation":"Both ends cannot have the same polarity, and the north is closer to the original north of the original piece, same with the south.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2000>43","subject":"Physics","year":"2000","type":"Objective","topic":"ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION","question":"A device used to prevent wearing away of the make-and -break contacts of an induction coil is called a/an","images":[],"options":{"A":"fuse","B":"electroscope","C":"resisitor","D":"capacitor"},"answer":"D","explanation":"A capacitor is connected across the make and break contacts, and helps the field to die off much rapidly.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2000>44","subject":"Physics","year":"2000","type":"Objective","topic":"ELECTROMAGNETIC FIELD : INDUCTANCE","question":"An inductor of inductance 10H carries a current of 0.2A calculate the energy stored in the inductor.","images":[],"options":{"A":"0.1J","B":"0.2J","C":"1.0J","D":"2.0J"},"answer":"B","explanation":"Energystoredinaninductor=12LI2  =12x10x(0.2)2=0.2J","marks":"1","difficulty":"2"},{"id":"objective>Physics>2000>45","subject":"Physics","year":"2000","type":"Objective","topic":"SIMPLE A.C. CIRCUITS : REACTANCE AND IMPEDANCE","question":"Calculate the inductance of an inductor whose reactance is one ohm at 50Hz","images":[],"options":{"A":"2.00 \u00d7102H","B":"6.36 \u00d7 103H","C":"3.18 \u00d7 10-3H","D":"4.55 \u00d7 104 H"},"answer":"C","explanation":"XL = 2\u03c0fL  Making L the subject of formular  L=XL2\u03c0F  L=72 x 22 x 50=744 x 50 = 3.18 x 10-3H","marks":"1","difficulty":"3"},{"id":"objective>Physics>2000>46","subject":"Physics","year":"2000","type":"Objective","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"Bohr's theory provides evidence for the","images":[],"options":{"A":"structure of the atom","B":"positive charge of an electron","C":"existence of energy level in the atom","D":"positive charge on the proton"},"answer":"C","explanation":"Bohr's theory, also known as Bohr's model of the atom, provides evidence for the existence of energy levels in the atom. According to this theory, electrons orbit the nucleus in specific energy levels, and can absorb or emit energy when they transition between these levels.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2000>47","subject":"Physics","year":"2000","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : RADIOACTIVITY","question":"A nuclide 20284Y emits in succession a \u03b1-particles and a \u03b2 -particles. the atomic number of the resulting nuclide is","images":[],"options":{"A":"198","B":"83","C":"82","D":"80"},"answer":"B","explanation":"42He = \u03b1  \u03b2 = 0-1e  20284Y \u2192 42He + 0-1e  20284Y \u2192 19882Z + 42He  19882Z \u2192 19883A + 0-1e    Therefore, 82 - (-1) = 83","marks":"1","difficulty":"2"},{"id":"objective>Physics>2000>48","subject":"Physics","year":"2000","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : RADIOACTIVITY","question":"The half life of a radioactive substance is 14days. if 48g of this substance is stored, after how many days will 1.5g of the original substance remain ?","images":[],"options":{"A":"84 days","B":"70 days","C":"56 days","D":"40 days"},"answer":"B","explanation":"4824  12  6  3  1.51 half life  2 half life  3 half life  4 half life  5 half life  5 half life = 5 x 14 = 70 days","marks":"1","difficulty":"2"},{"id":"objective>Physics>2000>49","subject":"Physics","year":"2000","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : FUSION AND FISSION","question":"A material of mass 1.0 \u00d7 103 kg undergoes a fission process which decreases its mass by 0.02 percent. calculate the amount of energy released in the process [c = 3.0 \u00d7 108ms-1]","images":[],"options":{"A":"1.8 \u00d7 1020 J","B":"1.8 \u00d7 1013 J","C":"1.8 \u00d7 1012 J","D":"1.8 \u00d7 1010 J"},"answer":"C","explanation":"E = \u0394Mc2  0.02 x 1.0 x 10-3 x (3.0 x 108)2  2.0 x 10-5 x 9.0 x 1016  1.8 x 1012J","marks":"1","difficulty":"3"},{"id":"objective>Physics>2000>50","subject":"Physics","year":"2000","type":"Objective","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"Absorption line spectra exhibited by atoms is a result of","images":[],"options":{"A":"change in the kinetic energy of a moving atom","B":"instability of the nucleons","C":"excation of an electron in the atom","D":"transition of an electron from a higher to lower energy level"},"answer":"D","explanation":"Absorption line spectra are produced when an electron absorbs energy and transitions from a lower energy level to a higher energy level within an atom. When the electron returns to its original energy level, it emits a photon of light. The energy of this photon corresponds to a specific wavelength of light, which appears as a line in the absorption spectrum. Therefore, the correct answer is 'transition of an electron from a higher to lower energy level'.","marks":"1","difficulty":"2"}];